import { NextRequest, NextResponse } from "next/server";
import { writeFile } from "fs/promises";
import path from "path";
import fs from "fs/promises";
import { PdfReader } from "pdfreader";
import Tesseract from "tesseract.js";
import { exec } from "child_process";
import { promisify } from "util";

const uploadDir = path.join(process.cwd(), "public", "uploads");
const execPromise = promisify(exec);

async function ensureUploadDir() {
  try {
    await fs.access(uploadDir);
  } catch {
    await fs.mkdir(uploadDir, { recursive: true });
  }
}

// Extract text using pdfreader
async function extractTextFromPDF(buffer: Buffer): Promise<string | null> {
  return new Promise((resolve, reject) => {
    const reader = new PdfReader();
    let text = "";

    reader.parseBuffer(buffer, (err, item) => {
      if (err) {
        reject(err);
      } else if (!item) {
        resolve(text.trim() || null); // End of file
      } else if (item.text) {
        text += item.text + " ";
      }
    });
  });
}

// Convert PDF to Image (First Page) for OCR
async function convertPDFToImage(
  pdfPath: string,
  imagePath: string
): Promise<void> {
  try {
    await execPromise(
      `pdftoppm -png -singlefile ${pdfPath} ${imagePath.replace(".png", "")}`
    );
  } catch (error) {
    console.error("Error converting PDF to image:", error);
    throw new Error("Failed to convert PDF to image");
  }
}

// Perform OCR using Tesseract.js
async function extractTextUsingOCR(imagePath: string): Promise<string> {
  try {
    const { data } = await Tesseract.recognize(imagePath, "eng");
    return data.text.trim();
  } catch (error) {
    console.error("Error extracting text via OCR:", error);
    throw new Error("OCR extraction failed");
  }
}

// Detect if extracted text is a marksheet
function isMarksheet(text: string): boolean {
  const lowerText = text.toLowerCase();
  const keywords = [
    "marks",
    "percentage",
    "subject",
    "total",
    "obtained",
    "grade",
    "score",
    "cgpa",
    "sgpa",
    "pass",
    "fail",
  ];
  const keywordCount = keywords.filter((keyword) =>
    lowerText.includes(keyword)
  ).length;
  const percentagePattern = /\b\d{1,3}\.\d{1,2}%\b/;
  const marksPattern = /\b\d{1,3}\/\d{1,3}\b/;
  return (
    keywordCount >= 3 ||
    percentagePattern.test(lowerText) ||
    marksPattern.test(lowerText)
  );
}

export async function POST(req: NextRequest) {
  try {
    await ensureUploadDir();
    const contentType = req.headers.get("content-type") || "";

    if (!contentType.includes("multipart/form-data")) {
      return NextResponse.json(
        { message: "Invalid content type" },
        { status: 400 }
      );
    }

    const formData = await req.formData();
    const file = formData.get("file");

    if (!file || !(file instanceof File)) {
      return NextResponse.json(
        { message: "No file provided" },
        { status: 400 }
      );
    }

    if (file.size === 0) {
      return NextResponse.json(
        { message: "Uploaded file is empty" },
        { status: 400 }
      );
    }

    const bytes = await file.arrayBuffer();
    const buffer = Buffer.from(bytes);
    const uniqueFilename = `${Date.now()}-${file.name}`;
    const pdfPath = path.join(uploadDir, uniqueFilename);
    const imagePath = pdfPath.replace(".pdf", ".png");

    await writeFile(pdfPath, buffer);

    let extractedText = await extractTextFromPDF(buffer);

    // If no text found, use OCR
    if (!extractedText) {
      console.log("No text found, using OCR...");
      await convertPDFToImage(pdfPath, imagePath);
      extractedText = await extractTextUsingOCR(imagePath);
    }

    const marksheetDetected = isMarksheet(extractedText);

    return NextResponse.json({
      text: extractedText,
      filename: uniqueFilename,
      isMarksheet: marksheetDetected
        ? "Yes, this appears to be a marksheet."
        : "No, this does not appear to be a marksheet.",
    });
  } catch (error) {
    console.error("Error processing file:", error);
    return NextResponse.json(
      { message: "Error processing file" },
      { status: 500 }
    );
  }
}
